package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class LinkedTreeMapTest {

  private LinkedTreeMap<String, String> map;

  @BeforeEach
  void setUp() {
    map = new LinkedTreeMap<>();
  }

  @Test
  void size_whenEmpty_returnsZero() {
    assertEquals(0, map.size());
  }

  @Test
  void size_afterPutIncreasesSize() {
    map.put("key1", "value1");
    assertEquals(1, map.size());
    map.put("key2", "value2");
    assertEquals(2, map.size());
  }

  @Test
  void size_afterPutSameKeyDoesNotIncreaseSize() {
    map.put("key1", "value1");
    assertEquals(1, map.size());
    map.put("key1", "value2");
    assertEquals(1, map.size());
  }

  @Test
  void size_afterRemoveDecreasesSize() {
    map.put("key1", "value1");
    map.put("key2", "value2");
    assertEquals(2, map.size());
    map.remove("key1");
    assertEquals(1, map.size());
    map.remove("key2");
    assertEquals(0, map.size());
  }

  @Test
  void size_afterClearIsZero() {
    map.put("key1", "value1");
    map.put("key2", "value2");
    assertEquals(2, map.size());
    map.clear();
    assertEquals(0, map.size());
  }
}
